import HomePage from './pages/HomePage';
import CategoryPage from './pages/CategoryPage';
import CompanyPage from './pages/CompanyPage';
import LoginPage from './pages/LoginPage';
import ProductPage from './pages/ProductPage';

const routes = [
  { path: '/',                    element: HomePage,      exact: true },
  // New SEO-friendly routes
  { path: '/:city/:categorySlug', element: CategoryPage },
  { path: '/:slug',              element: CompanyPage },  // Will handle company slugs
  { path: '/:slug',              element: ProductPage },  // Will handle product slugs
  // Backward compatibility routes (old patterns)
  { path: '/category/:city/:query', element: CategoryPage },
  { path: '/company/:id?',        element: CompanyPage },
  { path: '/product/:productId',  element: ProductPage },
  { path: '/login',               element: LoginPage },
];

export default routes;
